import React from "react";
import { STATUS_COLORS, capitalize } from "../utils/helpers";

export function UrgencyBadge({ urgency }) {
  const cls = { high: "badge-red", medium: "badge-yellow", low: "badge-green" }[urgency] || "badge-gray";
  return <span className={`badge ${cls}`}>{capitalize(urgency)}</span>;
}

export function CategoryBadge({ category }) {
  return <span className="badge badge-blue">{capitalize(category)}</span>;
}

export function StatusBadge({ status }) {
  const s = STATUS_COLORS[status] || STATUS_COLORS.pending;
  return (
    <span className="badge" style={{ background: s.bg, color: s.color }}>
      {capitalize(status)}
    </span>
  );
}
